import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const CustomerViewOrders = () => {
    const [orders, setOrders] = useState([]);
    const [message, setMessage] = useState('');
    const navigate = useNavigate();
    const customerId = sessionStorage.getItem("customerid");

    useEffect(() => {
        if (!customerId) {
            navigate("/customer/signin");
            return;
        }

        axios.post("http://localhost:3001/customer/vieworders", { customerId })
            .then(response => {
                if (Array.isArray(response.data)) {
                    setOrders(response.data);
                } else if (response.data.message) {
                    setMessage(response.data.message);
                    setOrders([]);
                }
            })
            .catch(err => {
                console.error("Error fetching orders:", err);
                alert("Could not fetch your orders.");
            });
    }, [customerId, navigate]);

    return (
        <div className="container">
            <h2 className="mt-3">Your Past Orders</h2>
            <div className="row g-3 mt-3">
                {orders.length > 0 ? orders.map(order => (
                    <div key={order._id} className="col col-12 col-sm-12 col-md-12 col-lg-12 col-xl-12 col-xxl-12">
                        <div className="card mb-3">
                            <div className="card-header">
                                <div className="d-flex justify-content-between">
                                    <div><strong>Order ID:</strong> {order._id}</div>
                                    <div><strong>Date:</strong> {new Date(order.orderDate).toLocaleDateString()}</div>
                                </div>
                            </div>
                            <div className="card-body">
                                <table className="table table-sm">
                                    <thead>
                                        <tr>
                                            <th scope="col">Product</th>
                                            <th scope="col">Quantity</th>
                                            <th scope="col">Unit Price</th>
                                            <th scope="col">Subtotal</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {order.items.map(item => (
                                            <tr key={item._id}>
                                                <td>{item.productId ? item.productId.name : 'Product not found'}</td>
                                                <td>{item.quantity}</td>
                                                <td>${item.productId ? item.productId.price.toFixed(2) : 'N/A'}</td>
                                                <td>${item.productId ? (item.productId.price * item.quantity).toFixed(2) : 'N/A'}</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                            <div className="card-footer text-end">
                                <h5>Order Total: ${order.totalAmount.toFixed(2)}</h5>
                            </div>
                        </div>
                    </div>
                )) : (
                    <div className="col">
                        <p>{message || 'You have no past orders.'}</p>
                    </div>
                )}
            </div>
        </div>
    );
};

export default CustomerViewOrders;
